package main

import (
	"context"
	"sync"
)

func Fetch(ctx context.Context, urls []string, fetch func(string) string) []string {
	out := make(chan string, len(urls))
	var wg sync.WaitGroup
	for _, u := range urls {
		wg.Add(1)
		go func(u string) {
			defer wg.Done()
			out <- fetch(u)
		}(u)
	}
	wg.Wait()
	close(out)
	res := []string{}
	for s := range out {
		res = append(res, s)
	}
	return res
}

use std::sync::{Arc, Mutex};

pub struct Counter(Arc<Mutex<u64>>);

impl Counter {
    pub fn inc(&self) {
        let mut g = self.0.lock().unwrap();
        *g += 1;
    }
}
